#include <stdio.h>
#include <stdlib.h>
#include <string.h>

#define MAXN 100
#define MAXM 1000
#define MAXF 10000

int n, m, t, k;
int r[MAXN], b[MAXN], g[MAXN], min_g[MAXN], ti[MAXN];
int graph[MAXN][MAXN];

int max_flow(int s, int t) {
    int flow = 0;
    while (1) {
        int parent[MAXN];
        memset(parent, -1, sizeof(parent));
        int queue[MAXN];
        int front = 0, rear = 0;
        queue[rear++] = s;
        while (front < rear) {
            int u = queue[front++];
            for (int v = 0; v < n; v++) {
                if (graph[u][v] > 0 && parent[v] == -1) {
                    parent[v] = u;
                    queue[rear++] = v;
                }
            }
        }
        if (parent[t] == -1) break;
        int path_flow = MAXF;
        for (int v = t; v != s; v = parent[v]) {
            int u = parent[v];
            path_flow = min(path_flow, graph[u][v]);
        }
        for (int v = t; v != s; v = parent[v]) {
            int u = parent[v];
            graph[u][v] -= path_flow;
            graph[v][u] += path_flow;
        }
        flow += path_flow;
    }
    return flow;
}

int main() {
    scanf("%d", &t);
    while (t--) {
        scanf("%d %d", &n, &m);
        for (int i = 0; i < n; i++) {
