        }
        for (int i = 0; i < n; i++) {
            scanf("%d", &b[i]);
        }
        for (int i = 0; i < n; i++) {
            scanf("%d", &g[i]);
        }
        for (int i = 0; i < n; i++) {
            scanf("%d", &ti[i]);
        }
        for (int i = 0; i < n; i++) {
            scanf("%d", &min_g[i]);
        }
        scanf("%d", &k);
        for (int i = 0; i < m; i++) {
            int u, v;
            scanf("%d %d", &u, &v);
            graph[u - 1][v - 1] = 1;
            graph[v - 1][u - 1] = 1;
        }
        int s = n, t = n + 1;
        for (int i = 0; i < n; i++) {
            graph[s][i] = r[i];
            graph[i][t] = min_g[i];
        }
        int flow = max_flow(s, t);
        if (flow >= k) {
            printf("1\n");
        } else {
            printf("0\n");
        }
    }
    return 0;
}

