    static final int MAXF = 10000;
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int t = sc.nextInt();
        while (t-- > 0) {
            int n = sc.nextInt();
            int m = sc.nextInt();
            int[] r = new int[n];
            int[] b = new int[n];
            int[] g = new int[n];
            int[] min_g = new int[n];
            int[] ti = new int[n];
            for (int i = 0; i < n; i++) r[i] = sc.nextInt();
            for (int i = 0; i < n; i++) b[i] = sc.nextInt();
            for (int i = 0; i < n; i++) g[i] = sc.nextInt();
            for (int i = 0; i < n; i++) ti[i] = sc.nextInt();
            for (int i = 0; i < n; i++) min_g[i] = sc.nextInt();
            int k = sc.nextInt();
            int[][] graph = new int[n][n];
            for (int i = 0; i < m; i++) {
                int u = sc.nextInt() - 1;
                int v = sc.nextInt() - 1;
                graph[u][v] = 1;
                graph[v][u] = 1;
            }
            int s = n;
            int t = n + 1;
            for (int i = 0; i < n; i++) {
                graph[s][i] = r[i];
                graph[i][t] = min_g[i];
            }
            int flow = max_flow(graph, s, t);
            if (flow >= k) System.out.println("1");
            else System.out.println("0");
        }
    }
    public static int max_flow(int[][] graph, int s, int t) {
        int flow = 0;
        while (true) {
            int[] parent = new int[graph.length];
            Arrays.fill(parent, -1);
            Queue<Integer> q = new LinkedList<>();
            q.add(s);
            while (!q.isEmpty()) {
                int u = q.poll();
                for (int v = 0; v < graph.length; v++) {
                    if (graph[u][v] > 0 && parent[v] == -1) {
                        parent[v] = u;
                        q.add(v);
                    }
                }
            }
            if (parent[t] == -1) break;
            int path_flow = Integer.MAX_VALUE;
            for (int v = t; v != s; v = parent[v]) {
                int u = parent[v];
                path_flow = Math.min(path_flow, graph[u][v]);
            }
            for (int v = t; v != s; v = parent[v]) {
                int u = parent[v];
                graph[u][v] -= path_flow;
                graph[v][u] += path_flow;
            }
            flow += path_flow;
        }
        return flow;
    }
}
